import{_ as s,o as n,c as i,a2 as e}from"./chunks/framework.Bix3-HpO.js";const g=JSON.parse('{"title":"Review Page Blocks","description":"Spinoko Theme Review Page Blocks","frontmatter":{"title":"Review Page Blocks","description":"Spinoko Theme Review Page Blocks","weight":50,"extra":{"order":50},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/spinoko/casino-page-blocks"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/spinoko/casino-page-blocks"}],["meta",{"property":"og:title","content":"Review Page Blocks"}],["meta",{"property":"og:description","content":"Spinoko Theme Review Page Blocks"}],["meta",{"name":"twitter:title","content":"Review Page Blocks"}],["meta",{"name":"twitter:description","content":"Spinoko Theme Review Page Blocks"}]]},"headers":[],"relativePath":"docs/spinoko/casino-page-blocks.md","filePath":"docs/spinoko/casino-page-blocks.md"}'),a={name:"docs/spinoko/casino-page-blocks.md"};function t(c,o,l,r,p,d){return n(),i("div",null,[...o[0]||(o[0]=[e('<h1 id="casino-review-page-blocks" tabindex="-1">Casino Review Page Blocks <a class="header-anchor" href="#casino-review-page-blocks" aria-label="Permalink to &quot;Casino Review Page Blocks&quot;">​</a></h1><p>Spinoko theme comes with built-in casino page blocks that you can use to easily present casino information.</p><hr><h2 id="using-blocks" tabindex="-1">Using Blocks <a class="header-anchor" href="#using-blocks" aria-label="Permalink to &quot;Using Blocks&quot;">​</a></h2><p>There are 9 blocks available for you to use in casino pages:</p><ol><li>Casino Ratings</li><li>Casino Games</li><li>Casino Countries</li><li>Casino Payments</li><li>Casino Game Providers</li><li>Casino CTA</li><li>Casino Info, Pros &amp; Cons Table</li><li>Casino Bonuses</li><li>Featured Bonus</li></ol><h3 id="casino-ratings-block" tabindex="-1">Casino Ratings Block <a class="header-anchor" href="#casino-ratings-block" aria-label="Permalink to &quot;Casino Ratings Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-casino-ratings.png" alt="spinoko-blocks-casino-ratings"></p><p>To add a new ratings block simply click on the <strong>+</strong> (Add block) sign and select <strong>Casino Ratings</strong> in <strong>Spinoko Blocks</strong> section.</p><p>No further configuration is required, just make sure to fill in <strong>Ratings</strong> fields in Casino Fields.</p><h3 id="casino-games-block" tabindex="-1">Casino Games Block <a class="header-anchor" href="#casino-games-block" aria-label="Permalink to &quot;Casino Games Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-casino-games.png" alt="spinoko-blocks-casino-games"></p><p>To add a new games block simply click on the <strong>+</strong> (Add block) sign and select <strong>Casino Games</strong> in <strong>Spinoko Blocks</strong> section.</p><p>You can also choose to display the casino logo with an affiliate link next to game icons.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-casino-games-admin.png" alt="spinoko-blocks-casino-games-admin"></p><h3 id="casino-countries-block" tabindex="-1">Casino Countries Block <a class="header-anchor" href="#casino-countries-block" aria-label="Permalink to &quot;Casino Countries Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-casino-countries.png" alt="spinoko-blocks-casino-countries"></p><p>To add a new countries block simply click on the <strong>+</strong> (Add block) sign and select <strong>Casino Countries</strong> in <strong>Spinoko Blocks</strong> section.</p><p>No further configuration is required, just make sure to fill in <strong>Payments</strong> fields in Casino Fields.</p><h3 id="casino-payments-block" tabindex="-1">Casino Payments Block <a class="header-anchor" href="#casino-payments-block" aria-label="Permalink to &quot;Casino Payments Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-casino-payments.png" alt="spinoko-blocks-casino-payments"></p><p>To add a new payments block simply click on the <strong>+</strong> (Add block) sign and select <strong>Casino Payments</strong> in <strong>Spinoko Blocks</strong> section.</p><p>No further configuration is required, just make sure to fill in <strong>Payments</strong> fields in Casino Fields.</p><h3 id="casino-game-providers-block" tabindex="-1">Casino Game Providers Block <a class="header-anchor" href="#casino-game-providers-block" aria-label="Permalink to &quot;Casino Game Providers Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-casino-game-providers.png" alt="spinoko-blocks-casino-game-providers"></p><p>To add a new game providers block simply click on the <strong>+</strong> (Add block) sign and select <strong>Casino Game Providers</strong> in <strong>Spinoko Blocks</strong> section.</p><p>No further configuration is required, just make sure to fill in <strong>Game Providers</strong> fields in Casino Fields.</p><h3 id="casino-cta-block" tabindex="-1">Casino CTA Block <a class="header-anchor" href="#casino-cta-block" aria-label="Permalink to &quot;Casino CTA Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-casino-cta.png" alt="spinoko-blocks-casino-cta"></p><p>To add a new CTA block simply click on the <strong>+</strong> (Add block) sign and select <strong>Casino CTA</strong> in <strong>Spinoko Blocks</strong> section.</p><p>Fill in the CTA fields such as heading and content, button anchor text and the rest will be generated for you from the casino fields.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-casino-cta-admin.png" alt="spinoko-blocks-casino-cta-admin"></p><h3 id="casino-info-pros-cons-block" tabindex="-1">Casino Info-Pros-Cons Block <a class="header-anchor" href="#casino-info-pros-cons-block" aria-label="Permalink to &quot;Casino Info-Pros-Cons Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-casino-info-pros-cons.png" alt="spinoko-blocks-casino-info-pros-cons"></p><p>To add a new block simply click on the <strong>+</strong> (Add block) sign and select <strong>Casino Info, Pros &amp; Cons</strong> in <strong>Spinoko Blocks</strong> section.</p><p>No further configuration is required, just make sure to fill in <strong>Info</strong>, as well as <strong>Pros and Cons</strong> fields in Casino Fields.</p><h3 id="casino-bonuses-block" tabindex="-1">Casino Bonuses Block <a class="header-anchor" href="#casino-bonuses-block" aria-label="Permalink to &quot;Casino Bonuses Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-casino-bonuses.png" alt="spinoko-blocks-casino-bonuses"></p><p>To add a new block simply click on the <strong>+</strong> (Add block) sign and select <strong>Casino Bonuses</strong> in <strong>Spinoko Blocks</strong> section.</p><p>Adjust general block settings and add as many bonuses as you want by filling in bonus details. For each bonus you can add a unique affiliate link or use the default link URL.</p><p>There are 2 custom fields for you to use in this block. First you define the fields by setting their labels on top of the bonus list and then you fill in their respective values for each bonus.</p><p>You can choose to display the casino logo or a simple bonus/gift icon on each row, you can also choose how to display the terms. One option is to not display them. The second option is &quot;link&quot; in which case you need to fill in the terms link URL in the &quot;Terms&quot; field in the bonus list. And the last and default option is &quot;popover&quot; in which case you add the terms text in the &quot;Terms&quot; field.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-casino-bonuses-admin.png" alt="spinoko-blocks-casino-bonuses"></p><blockquote><p>Casino Bonuses block can also be used on other, not casino review, pages.</p></blockquote><hr><h3 id="featured-bonus-block" tabindex="-1">Featured Bonus Block <a class="header-anchor" href="#featured-bonus-block" aria-label="Permalink to &quot;Featured Bonus Block&quot;">​</a></h3><p><code>💁 since version 2.9.0</code></p><p>You can create and display a featured bonus block on your review pages. It can feature the existing main bonus, or you can add a new one right in the block fields. You can customize the block fields such as button text, bonus heading, terms type, as well we overwrite the affiliate link.</p><blockquote><p>Featured Bonus block can also be used on other, not casino review, pages.</p></blockquote>',49)])])}const m=s(a,[["render",t]]);export{g as __pageData,m as default};
